/** Idempotent: seed sources, intervals, disable/re-enable sets, URL migrations, removed-id cleanup, aliases. */
export async function seedSources(db: D1Database): Promise<void> {
  const now = Math.floor(Date.now() / 1000);
  const stmt = db.prepare(
    `INSERT OR IGNORE INTO sources
       (id, name, source_type, company_handle, base_url, enabled, created_at)
     VALUES (?, ?, ?, ?, ?, 1, ?)`
  );

  // D1 `batch()` payload limit — chunk INSERTs.
  const stmts = SEED_SOURCES.map((s) =>
    stmt.bind(s.id, s.name, s.source_type, s.company_handle, s.base_url, now)
  );
  for (let i = 0; i < stmts.length; i += 100) {
    await db.batch(stmts.slice(i, i + 100));
  }

  // Batched UPDATES (intervals, flags).
  const intervalStmt = db.prepare("UPDATE sources SET fetch_interval_hours = ? WHERE id = ?");
  for (let i = 0; i < FETCH_INTERVALS.length; i += 100) {
    await db.batch(
      FETCH_INTERVALS.slice(i, i + 100).map(({ id, hours }) => intervalStmt.bind(hours, id))
    );
  }

  const disableStmt = db.prepare("UPDATE sources SET enabled = 0 WHERE id = ?");
  for (let i = 0; i < DISABLED_SOURCE_IDS.length; i += 100) {
    await db.batch(
      DISABLED_SOURCE_IDS.slice(i, i + 100).map((id) => disableStmt.bind(id))
    );
  }

  // One-off source row fixes (batched).
  await db.batch([
    // Workday CXS URLs verified 2026-03.
    db.prepare(`UPDATE sources SET base_url = ?, enabled = 1, last_error = NULL WHERE id = 'wd-bofa'`)
      .bind("https://ghr.wd1.myworkdayjobs.com/wday/cxs/ghr/lateral-us/jobs"),
    db.prepare(`UPDATE sources SET base_url = ?, enabled = 1, last_error = NULL WHERE id = 'wd-fedex'`)
      .bind("https://fedex.wd1.myworkdayjobs.com/wday/cxs/fedex/FXE-LAC_External_Career_Site/jobs"),
    db.prepare(`UPDATE sources SET base_url = ?, enabled = 1, last_error = NULL WHERE id = 'wd-morganstanley'`)
      .bind("https://ms.wd5.myworkdayjobs.com/wday/cxs/ms/External/jobs"),
    // IBM: switch from browser to public search API.
    db.prepare(`UPDATE sources SET name = ?, source_type = ?, base_url = ?, enabled = 1, last_error = NULL WHERE id = 'br-ibm'`)
      .bind("IBM", "ibm_careers", "https://www-api.ibm.com/search/api/v2"),
    // Starbucks: replace legacy browser placeholder with Eightfold PCS API.
    db.prepare(`UPDATE sources SET name = ?, source_type = ?, base_url = ?, enabled = 1, last_error = NULL WHERE id = 'br-starbucks'`)
      .bind("Starbucks (Eightfold)", "eightfold", "https://starbucks.eightfold.ai/careers?domain=starbucks.com"),
    // Apple: switch to HTML search.
    db.prepare(`UPDATE sources SET name = ?, base_url = ?, enabled = 1, last_error = NULL WHERE id = 'apl-global'`)
      .bind("Apple", "https://jobs.apple.com/en-us/search?location=united-states-USA"),
    // KinderCare: Phenom at kcecareers.com.
    db.prepare(`UPDATE sources SET name = ?, source_type = ?, base_url = ?, enabled = 1, last_error = NULL WHERE id = 'wb-kindercare'`)
      .bind("KinderCare (Phenom)", "phenom", "https://www.kcecareers.com/us/en/"),
    // Hilton: browser placeholder → Phenom (`jobs.hilton.com` sitemap + `phApp.ddo` job detail).
    db.prepare(`UPDATE sources SET name = ?, source_type = ?, base_url = ?, enabled = 1, last_error = NULL WHERE id = 'br-hilton'`)
      .bind("Hilton (Phenom)", "phenom", "https://jobs.hilton.com/us/en/"),
    // FedEx: browser placeholder → Paradox (listing + sitemap on careers.fedex.com; avoid WAF’d paradox.ai fetches).
    db.prepare(`UPDATE sources SET name = ?, source_type = ?, base_url = ?, enabled = 1, last_error = NULL WHERE id = 'br-fedex'`)
      .bind("FedEx (Paradox)", "paradox", "https://careers.fedex.com/jobs"),
    // Meta: browser source superseded by single-companies/meta.ts fetcher.
    db.prepare("UPDATE sources SET enabled = 0 WHERE id = 'br-meta'"),
    // Rename legacy single-employer source_type values (idempotent).
    db.prepare("UPDATE sources SET source_type = 'uber' WHERE source_type = 'uber_sites'"),
    db.prepare("UPDATE sources SET source_type = 'shopify' WHERE source_type = 'shopify_careers'"),
    db.prepare("UPDATE sources SET source_type = 'hca' WHERE source_type = 'hca_careers'"),
    db.prepare("UPDATE sources SET source_type = 'aramark' WHERE source_type = 'aramark_careers'"),
    db.prepare("UPDATE sources SET source_type = 'lvmh' WHERE source_type = 'lvmh_algolia'"),
    db.prepare("UPDATE sources SET source_type = 'meta' WHERE source_type = 'metacareers'"),
    // Taleo InFlight: rename source_type from hyatt → taleo (fetcher is ATS-generic).
    db.prepare("UPDATE sources SET source_type = 'taleo' WHERE source_type = 'hyatt'"),
    db.prepare(`UPDATE sources SET base_url = ? WHERE id = 'hy-hyatt'`).bind(
      "https://careers.hyatt.com/en-US/careers/search?searchable=%5B%5D&portals=21860210089,22260210089,68160210089"
    ),
    // Insperity: careers site is Workday (NSP); legacy rows may still be source_type workable + Workable widget URL.
    db.prepare(
      `UPDATE sources SET name = 'Insperity (Workday)', source_type = 'workday', base_url = ?, enabled = 1, last_error = NULL WHERE id = 'wb-insperity'`
    ).bind("https://insperity.wd12.myworkdayjobs.com/wday/cxs/insperity/NSP/jobs"),
    // Guess (BrassRing): disable legacy `br-guess` row if seeded manually; canonical is `brg-guess`.
    db.prepare("UPDATE sources SET enabled = 0 WHERE id = 'br-guess'"),
  ]);

  // Removed ids — delete jobs then sources (FK).
  const removedSectorBoardIds = [
    "rss-he-bundle",
    "rss-he-main",
    "rss-he-faculty",
    "rss-he-admin",
    "rss-he-it",
  ];
  const removedLegacySourceIds = [
    "gh-grammarly",
    "ab-superhuman",
    "rf-recruitingfromscratch",
    "br-adp", // superseded by ac-adp (MyJobs CX)
    "br-marriott", // superseded by ce-marriott (Oracle CE)
    "br-pepsico", // superseded by ac-pepsico-pbna (ADP CX) + jibe-pepsico (iCIMS)
  ];
  const allRemovedIds = [...removedSectorBoardIds, ...removedLegacySourceIds];
  await db.batch([
    ...allRemovedIds.map((id) => db.prepare("DELETE FROM jobs WHERE source_id = ?").bind(id)),
    ...allRemovedIds.map((id) => db.prepare("DELETE FROM sources WHERE id = ?").bind(id)),
    db.prepare(
      "DELETE FROM company_aliases WHERE alias_slug = 'recruitingfromscratch' OR canonical_slug = 'recruitingfromscratch'"
    ),
    db.prepare(
      "DELETE FROM companies WHERE slug = 'recruitingfromscratch' AND NOT EXISTS (SELECT 1 FROM jobs j WHERE j.company_id = companies.id)"
    ),
  ]);

  // Re-enable replacements.
  const enableStmt = db.prepare("UPDATE sources SET enabled = 1, last_error = NULL WHERE id = ?");
  for (let i = 0; i < ENABLED_REPLACEMENT_SOURCE_IDS.length; i += 100) {
    await db.batch(
      ENABLED_REPLACEMENT_SOURCE_IDS.slice(i, i + 100).map((id) => enableStmt.bind(id))
    );
  }

  // Company aliases
  const aliasStmt = db.prepare(
    "INSERT OR IGNORE INTO company_aliases (alias_slug, canonical_slug) VALUES (?, ?)"
  );
  await db.batch(
    COMPANY_ALIASES.map(({ alias, canonical }) => aliasStmt.bind(alias, canonical))
  );
}

/** `ab-crunchbase` → `tt-crunchbase`; rekey `jobs.id`; clear embeddings. No-op if legacy row missing. */
export async function migrateRenameCrunchbaseSource(db: D1Database): Promise<void> {
  const oldId = CRUNCHBASE_SOURCE_LEGACY_ID;
  const newId = CRUNCHBASE_SOURCE_ID;

  const oldSource = await db
    .prepare("SELECT id FROM sources WHERE id = ?")
    .bind(oldId)
    .first<{ id: string }>();
  if (!oldSource) return;

  const newExists = await db
    .prepare("SELECT id FROM sources WHERE id = ?")
    .bind(newId)
    .first<{ id: string }>();

  if (!newExists) {
    await db
      .prepare(
        `INSERT INTO sources (id, name, source_type, company_handle, base_url, enabled, last_fetched_at, last_job_count, last_error, fetch_interval_hours, created_at)
         SELECT ?, name, source_type, company_handle, base_url, enabled, last_fetched_at, last_job_count, last_error, fetch_interval_hours, created_at
         FROM sources WHERE id = ?`
      )
      .bind(newId, oldId)
      .run();
  }

  const jobs = await db
    .prepare("SELECT id, external_id FROM jobs WHERE source_id = ?")
    .bind(oldId)
    .all<{ id: string; external_id: string }>();

  for (const row of jobs.results ?? []) {
    const newJobId = buildJobId(newId, row.external_id);
    if (newJobId === row.id) {
      await db
        .prepare("UPDATE jobs SET source_id = ?, embedding_generated_at = NULL WHERE id = ?")
        .bind(newId, row.id)
        .run();
    } else {
      await db
        .prepare(
          "UPDATE jobs SET id = ?, source_id = ?, embedding_generated_at = NULL WHERE id = ?"
        )
        .bind(newJobId, newId, row.id)
        .run();
    }
  }

  await db.prepare("DELETE FROM sources WHERE id = ?").bind(oldId).run();
}
